/**
 * Process-scoped UniFFI facade. One instance owns the multi-thread runtime.
 */
public protocol TableRockBridgeProtocol: AnyObject, Sendable {

    /**
     * Consumes and applies one reviewed structure change. Failed apply is not retryable.
     */
    func applyDdlChange(tokenId: Data, sessionId: Data, nowMs: UInt64, confirmed: Bool) throws  -> String

    /**
     * Consumes and applies one reviewed role change. Failed apply is not retryable.
     */
    func applyPostgresRoleChange(tokenId: Data, sessionId: Data, nowMs: UInt64, confirmed: Bool) throws  -> String

    /**
     * Consume-once authorize + apply by review-token handle (never plan bytes).
     *
     * Token is removed before apply; a failed apply cannot be retried with the
     * same handle (ambiguous-write non-retry / single-use authority).
     */
    func applyReviewToken(tokenId: Data, nowMs: UInt64, sessionId: Data, expectedRevision: UInt64) throws  -> ApplyOutcome

    /**
     * Consume-once authorize by review-token handle (never plan bytes).
     *
     * Returns the token id bytes on success for correlation; authority is
     * removed even when later apply fails (core registry contract).
     */
    func authorizeReviewToken(tokenId: Data, nowMs: UInt64, sessionId: Data, expectedRevision: UInt64) throws  -> Data

    func cancel(operationId: Data) throws  -> CancelOutcome

    /**
     * Request cancellation. The engine observes it at the next safe row boundary.
     */
    func cancelCsvImport(operationId: Data) throws  -> Bool

    /**
     * Requests cancellation; repeated requests remain safe.
     */
    func cancelPostgresTool(operationId: Data) throws  -> Bool

    /**
     * Requests cancellation. Repeated requests are safe.
     */
    func cancelRedisSubscription(operationId: Data) throws  -> Bool

    /**
     * Requests server-stream and file-writer cancellation.
     */
    func cancelStreamExport(operationId: Data) throws  -> Bool

    func cancelStreamExportInner(operationIdBytes: Data) throws  -> Bool

    /**
     * Executes one explicit driver health probe for a live session.
     */
    func checkSessionHealth(sessionId: Data) throws  -> BridgeSessionHealth

    /**
     * Attach a local-only persistence file for profile-backed open (idempotent replace).
     */
    func configurePersistence(path: String) throws

    func createProfileGroup(name: String) throws

    /**
     * Poll one bounded CSV import progress/outcome snapshot.
     */
    func csvImportProgress(operationId: Data) throws  -> BridgeCsvImportProgress

    func deleteNativeWindowIntent(windowId: String) throws

    /**
     * Revision-checked removal; active sessions remain alive.
     */
    func deleteProfile(profileId: Data, expectedRevision: UInt64) throws

    func deleteProfileGroup(name: String) throws  -> UInt32

    func deleteSavedQuery(queryId: Int64) throws  -> Bool

    func deleteSessionIntent(profileId: Data) throws

    /**
     * Drops the Tokio runtime after service shutdown. Idempotent.
     */
    func destroyRuntime() throws

    /**
     * Disconnect a session once no operation still holds it.
     */
    func disconnect(sessionId: Data) throws

    /**
     * Remove one terminal import snapshot after the client closes it.
     */
    func dismissCsvImport(operationId: Data) throws  -> Bool

    /**
     * Removes one terminal export snapshot.
     */
    func dismissStreamExport(operationId: Data) throws  -> Bool

    func dismissStreamExportInner(operationIdBytes: Data) throws  -> Bool

    /**
     * Removes terminal status. Running operations remain observable.
     */
    func dismissTableOperation(operationId: Data) throws  -> Bool

    /**
     * Ensures the Tokio runtime and service coordinator exist (idempotent).
     */
    func ensureRuntime() throws

    /**
     * Atomically exports all resident rows through the shared typed formatter.
     */
    func exportLoadedResult(resultId: Data, revision: UInt64, format: String, path: String) throws  -> UInt64

    /**
     * Atomically exports the closed safe-schema support manifest.
     */
    func exportSupportBundle(path: String) throws  -> UInt64

    /**
     * Fetches a resident page as version-1 encoded bytes.
     */
    func fetchPage(resultId: Data, startRow: UInt64, revision: UInt64) throws  -> Data

    /**
     * Formats resident Rust-owned result pages for clipboard/export.
     * Scope is `cell`, `row`, or `loaded`; format is csv/tsv/json/markdown/sql_insert/sql_update.
     */
    func formatResultCopy(resultId: Data, revision: UInt64, scope: String, row: UInt64?, column: UInt32?, format: String) throws  -> String

    func getNativeWindowIntent(windowId: String) throws  -> BridgeNativeWindowIntent?

    /**
     * Loads one editable profile without resolving or returning credentials.
     */
    func getProfileDraft(profileId: Data) throws  -> BridgeProfileDraft

    func getSessionIntent(profileId: Data) throws  -> BridgeSessionIntent?

    func historyRetention() throws  -> String

    /**
     * Inspects named placeholders without retaining statement text.
     */
    func inspectNamedParameters(statement: String) throws  -> BridgeNamedParameterPlan

    func listCatalogFilterPresets(sessionId: Data, catalogNodeId: Data) throws  -> [BridgeSavedFilterPreset]

    /**
     * Lists newest local query-history entries with optional SQL-text search.
